class Solution {
public:
    int strongPasswordChecker(string password) {
        int missing_type = 3;
        bool has_lower = false, has_upper = false, has_digit = false;
        for (char c : password) {
            if (islower(c)) has_lower = true;
            else if (isupper(c)) has_upper = true;
            else if (isdigit(c)) has_digit = true;
        }
        if (has_lower) missing_type--;
        if (has_upper) missing_type--;
        if (has_digit) missing_type--;

        int one = 0, two = 0;
        int p = 2;
        while (p < password.size()) {
            if (password[p] == password[p-1] && password[p] == password[p-2]) {
                int length = 2;
                while (p + 1 < password.size() && password[p] == password[p+1]) {
                    p++;
                    length++;
                }
                if (length % 3 == 0) one++;
                else if (length % 3 == 1) two++;
            }
            p++;
        }

        if (password.size() < 6) {
            return max(missing_type, 6 - password.size());
        } else if (password.size() <= 20) {
            return max(missing_type, one);
        } else {
            int delete_count = password.size() - 20;
            one -= min(delete_count, one);
            two -= min(max(delete_count - one, 0), two * 2) / 2;
            two -= min(max(delete_count - one - 2 * two, 0), two);
            return delete_count + max(missing_type, one + two);
        }
    }
};

